import React, { useState, useEffect } from 'react';
import { View, Text, Button, AsyncStorage } from 'react-native';

const App = () => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);

  const login = async (username, password) => {
    try {
      // Simulating API call to get token and user data
      const response = await fetch('https://api.example.com/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const data = await response.json();
      setToken(data.token);
      setUser(data.user);
    } catch (error) {
      console.error(error);
    }
  };

  const logout = async () => {
    try {
      // Simulating API call to invalidate token
      const response = await fetch('https://api.example.com/logout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token }),
      });
      await AsyncStorage.removeItem('token');
      await AsyncStorage.removeItem('user');
      setToken(null);
      setUser(null);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    const getToken = async () => {
      try {
        const storedToken = await AsyncStorage.getItem('token');
        if (storedToken !== null) {
          setToken(storedToken);
        }
        const storedUser = await AsyncStorage.getItem('user');
        if (storedUser !== null) {
          setUser(JSON.parse(storedUser));
        }
      } catch (error) {
        console.error(error);
      }
    };
    getToken();
  }, []);

  useEffect(() => {
    if (token !== null && user !== null) {
      // Simulating API call to validate token
      const response = fetch('https://api.example.com/validate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token }),
      });
    }
  }, [token, user]);

  return (
    <View>
      {user === null ? (
        <Button title="Login" onPress={() => login('username', 'password')} />
      ) : (
        <>
          <Text>Welcome, {user.name}!</Text>
          <Button title="Logout" onPress={logout} />
        </>
      )}
    </View>
  );
};

export default App;